ensure_dir <- function(path) {
  if (!dir.exists(path)) dir.create(path, recursive = TRUE, showWarnings = FALSE)
}

write_tbl <- function(x, path) {
  ensure_dir(dirname(path))
  readr::write_csv(x, path, na = "")
  invisible(x)
}

write_text_file <- function(lines, path) {
  ensure_dir(dirname(path))
  writeLines(lines, con = path)
  invisible(path)
}

safe_scale <- function(x) {
  x <- suppressWarnings(as.numeric(x))
  s <- sd(x, na.rm = TRUE)
  m <- mean(x, na.rm = TRUE)
  if (!is.finite(s) || s == 0) return(rep(0, length(x)))
  (x - m) / s
}

safe_cor <- function(x, y, method = "pearson") {
  x <- suppressWarnings(as.numeric(x))
  y <- suppressWarnings(as.numeric(y))
  ok <- is.finite(x) & is.finite(y)
  if (sum(ok) < 4 || sd(x[ok]) == 0 || sd(y[ok]) == 0) return(NA_real_)
  suppressWarnings(cor(x[ok], y[ok], method = method))
}

format_p <- function(p) {
  case_when(
    is.na(p) ~ "p=NA",
    p < 0.001 ~ "p<.001",
    TRUE ~ paste0("p=", sub("^0", "", formatC(p, format = "f", digits = 3)))
  )
}

correlation_test_stats <- function(dat, x_col, y_col, label = NULL) {
  x <- suppressWarnings(as.numeric(dat[[x_col]]))
  y <- suppressWarnings(as.numeric(dat[[y_col]]))
  ok <- is.finite(x) & is.finite(y)
  x <- x[ok]
  y <- y[ok]
  out_label <- if (is.null(label)) x_col else label
  if (length(x) < 4 || sd(x) == 0 || sd(y) == 0) {
    return(tibble(
      label = out_label,
      n = length(x),
      pearson_r = NA_real_,
      pearson_p = NA_real_,
      spearman_rho = NA_real_,
      spearman_p = NA_real_
    ))
  }
  pearson <- suppressWarnings(cor.test(x, y, method = "pearson"))
  spearman <- suppressWarnings(cor.test(x, y, method = "spearman", exact = FALSE))
  tibble(
    label = out_label,
    n = length(x),
    pearson_r = unname(pearson$estimate),
    pearson_p = pearson$p.value,
    spearman_rho = unname(spearman$estimate),
    spearman_p = spearman$p.value
  )
}

prediction_metrics <- function(observed, predicted) {
  ok <- is.finite(observed) & is.finite(predicted)
  y <- observed[ok]
  p <- predicted[ok]
  if (length(y) < 3) {
    return(tibble(n = length(y), pearson_r = NA_real_, spearman_rho = NA_real_, rmse = NA_real_, mae = NA_real_, cv_r2_vs_mean = NA_real_))
  }
  baseline <- mean(y, na.rm = TRUE)
  tibble(
    n = length(y),
    pearson_r = safe_cor(y, p, "pearson"),
    spearman_rho = safe_cor(y, p, "spearman"),
    rmse = sqrt(mean((y - p)^2, na.rm = TRUE)),
    mae = mean(abs(y - p), na.rm = TRUE),
    cv_r2_vs_mean = 1 - sum((y - p)^2, na.rm = TRUE) / sum((y - baseline)^2, na.rm = TRUE)
  )
}

impute_numeric_median <- function(dat, cols) {
  cols <- cols[cols %in% names(dat)]
  dat %>%
    mutate(across(all_of(cols), ~{
      x <- suppressWarnings(as.numeric(.x))
      med <- median(x, na.rm = TRUE)
      if (!is.finite(med)) med <- 0
      replace_na(x, med)
    }))
}

make_formula <- function(outcome, predictors) {
  predictors <- predictors[!is.na(predictors) & predictors != ""]
  if (length(predictors) == 0) {
    as.formula(paste0(outcome, " ~ 1"))
  } else {
    as.formula(paste(outcome, "~", paste(predictors, collapse = " + ")))
  }
}

clean_name <- function(x) {
  x %>%
    str_replace_all("[^A-Za-z0-9]+", "_") %>%
    str_replace_all("_+", "_") %>%
    str_replace_all("^_|_$", "")
}

is_leakage_name <- function(x) {
  str_detect(
    str_to_lower(x),
    paste(c(
      "combz", "combinedstress", "stress_burden", "burden", "suscept", "resilien",
      "corticosterone", "cort", "sucrose", "spt", "phenotype", "endpoint",
      "zscore", "z_score", "delta_cort", "group_numeric", "classification",
      "predicted", "observed", "residual", "outcome"
    ), collapse = "|")
  )
}

classify_feature_domain <- function(feature_names) {
  f <- str_to_lower(feature_names)
  case_when(
    str_detect(f, "gamm|auc|slope|recovery|trajectory|movement|locomotor|activity|distance|velocity") ~ "psychomotor_trajectory",
    str_detect(f, "entropy|rmssd|acf|cv|fano|burst|instability|variability|regularity|predictability") ~ "temporal_organization",
    str_detect(f, "proximity|contact|social|network|degree|clustering|edge|partner|association") ~ "social_organization",
    str_detect(f, "inactive|inactivity|sleep|rest|bout|fragment|circadian|light|dark|phase|day|night") ~ "rest_circadian",
    str_detect(f, "hmm|state|transition|lyapunov|recurrence|dfa|nonlinear|sample_entropy|approx_entropy") ~ "state_nonlinear",
    TRUE ~ "other"
  )
}

pretty_systems_feature <- function(x) {
  x %>%
    str_replace("^.*__", "") %>%
    str_replace_all("_", " ") %>%
    str_replace("\\bacf1\\b", "ACF1") %>%
    str_replace("\\brmssd\\b", "RMSSD") %>%
    str_replace("\\bcv\\b", "CV") %>%
    str_squish() %>%
    str_to_sentence()
}

classify_model_domain_step <- function(model_name) {
  case_when(
    model_name == "Mean only" ~ "Reference",
    model_name == "Raw movement only" ~ "Psychomotor",
    model_name == "08b compact behavior" ~ "Temporal organization",
    model_name == "Psychomotor trajectory" ~ "Psychomotor",
    model_name == "Psychomotor + temporal" ~ "Temporal organization",
    model_name == "Psychomotor + temporal + social" ~ "Social organization",
    model_name == "Add rest/circadian" ~ "Rest/circadian",
    model_name == "Full systems compact" ~ "State dynamics",
    TRUE ~ "Other"
  )
}

