# FEATURE AUDIT AND DOMAIN SELECTION
# ------------------------------------------------

id_cols <- c("AnimalNum", "Group", "Sex", "BinLevel", "ProximityInput", "EarlyWindow", outcome_col)
all_numeric <- names(model_dat_raw)[vapply(model_dat_raw, is.numeric, logical(1))]
all_numeric <- setdiff(all_numeric, outcome_col)
all_numeric <- all_numeric[!is_leakage_name(all_numeric)]

feature_audit <- tibble(feature = all_numeric) %>%
  mutate(
    domain = classify_feature_domain(feature),
    domain_label = recode(domain, !!!domain_labels),
    feature_label = pretty_systems_feature(feature),
    nonmissing_fraction = map_dbl(feature, ~mean(is.finite(model_dat_raw[[.x]]))),
    sd = map_dbl(feature, ~sd(model_dat_raw[[.x]], na.rm = TRUE)),
    abs_cor_with_outcome = map_dbl(feature, ~abs(safe_cor(model_dat_raw[[.x]], model_dat_raw[[outcome_col]], "spearman"))),
    signed_cor_with_outcome = map_dbl(feature, ~safe_cor(model_dat_raw[[.x]], model_dat_raw[[outcome_col]], "spearman")),
    eligible = nonmissing_fraction >= min_nonmissing_fraction & is.finite(sd) & sd > 0 & domain != "other"
  ) %>%
  arrange(domain, desc(abs_cor_with_outcome))

feature_correlation_stats <- map_dfr(all_numeric, function(fc) {
  correlation_test_stats(model_dat_raw, fc, outcome_col, label = fc)
}) %>%
  rename(feature = label) %>%
  mutate(
    pearson_p_bh = p.adjust(pearson_p, method = "BH"),
    spearman_p_bh = p.adjust(spearman_p, method = "BH"),
    CorrelationUse = "Univariable feature-to-outcome association used for systems feature screening and plotted selected-feature correlations"
  )

feature_audit <- feature_audit %>%
  left_join(
    feature_correlation_stats %>%
      select(feature, pearson_r, pearson_p, pearson_p_bh, spearman_p, spearman_p_bh, CorrelationUse),
    by = "feature"
  )

