    group_by(Model, Method) %>%
    group_modify(~prediction_metrics(.x$observed, .x$predicted)) %>%
    ungroup() %>%
    arrange(desc(cv_r2_vs_mean), rmse) %>%
    mutate(
      Outcome = primary_outcome_label,
      BinLevel = bin_level,
      AnalysisUse = "exploratory_nonlinear_sensitivity"
    )
  write_tbl(rf_predictions, file.path(output_dir, "tables/nonlinear_sensitivity_loo_predictions.csv"))
  write_tbl(rf_performance, file.path(output_dir, "tables/nonlinear_sensitivity_performance.csv"))
  write_tbl(rf_predictions, file.path(output_dir, "tables/sensitivity/nonlinear_sensitivity_loo_predictions.csv"))
  write_tbl(rf_performance, file.path(output_dir, "tables/sensitivity/nonlinear_sensitivity_performance.csv"))
}

# ------------------------------------------------
# INCREMENTAL SUMMARY AGAINST RAW MOVEMENT
# ------------------------------------------------

raw_row <- main_performance %>% filter(Model == "Raw movement only") %>% slice(1)
mean_row <- main_performance %>% filter(Model == "Mean only") %>% slice(1)

incremental_summary <- main_performance %>%
  mutate(
    delta_cv_r2_vs_mean_only = cv_r2_vs_mean - mean_row$cv_r2_vs_mean[1],
    delta_rmse_vs_mean_only = rmse - mean_row$rmse[1],
    delta_cv_r2_vs_raw_movement = cv_r2_vs_mean - raw_row$cv_r2_vs_mean[1],
    delta_rmse_vs_raw_movement = rmse - raw_row$rmse[1],
    Interpretation = case_when(
      Model == "Raw movement only" ~ "Baseline biological signal from early raw movement",
      delta_rmse_vs_raw_movement < 0 & delta_cv_r2_vs_raw_movement > 0 ~ "Improves prediction beyond raw movement",
      delta_rmse_vs_raw_movement >= 0 ~ "Does not improve beyond raw movement",
      TRUE ~ "Uncertain"
    ),
    ManuscriptMessage = case_when(
      Model == "08b compact behavior" & Interpretation == "Improves prediction beyond raw movement" ~ "Temporal organization strengthens prediction beyond gross movement.",
      Model == "Full systems compact" & Interpretation == "Improves prediction beyond raw movement" ~ "Broader systems features refine, but do not replace, the movement baseline.",
      Model == "Raw movement only" ~ "Use as the anchor for all systems comparisons.",
      TRUE ~ "Report cautiously as domain-ladder context."
    )
  )

write_tbl(incremental_summary, file.path(output_dir, "tables/systems_ladder_incremental_summary.csv"))
write_tbl(incremental_summary, file.path(output_dir, "tables/models/systems_ladder_incremental_summary.csv"))

sex_specific_incremental_summary <- if (nrow(sex_specific_performance) > 0) {
  sex_specific_performance %>%
    group_by(SexModel) %>%
    group_modify(~{
      raw_row_sex <- .x %>% filter(Model == "Raw movement only") %>% slice(1)
      mean_row_sex <- .x %>% filter(Model == "Mean only") %>% slice(1)
      if (nrow(raw_row_sex) == 0 || nrow(mean_row_sex) == 0) return(tibble())
      .x %>%
        mutate(
          delta_cv_r2_vs_mean_only = cv_r2_vs_mean - mean_row_sex$cv_r2_vs_mean[1],
          delta_rmse_vs_mean_only = rmse - mean_row_sex$rmse[1],
          delta_cv_r2_vs_raw_movement = cv_r2_vs_mean - raw_row_sex$cv_r2_vs_mean[1],
          delta_rmse_vs_raw_movement = rmse - raw_row_sex$rmse[1],
          Interpretation = case_when(
            Model == "Raw movement only" ~ "Sex-specific baseline biological signal from early raw movement",
            delta_rmse_vs_raw_movement < 0 & delta_cv_r2_vs_raw_movement > 0 ~ "Improves sex-specific prediction beyond raw movement",
            delta_rmse_vs_raw_movement >= 0 ~ "Does not improve beyond raw movement within this sex",
            TRUE ~ "Uncertain"
          )
        )
    }) %>%
    ungroup()
} else {
  tibble()
}
write_tbl(sex_specific_incremental_summary, file.path(output_dir, "tables/systems_ladder_incremental_summary_by_sex.csv"))
write_tbl(sex_specific_incremental_summary, file.path(output_dir, "tables/models/systems_ladder_incremental_summary_by_sex.csv"))

